def canonical_hand(c1, c2):
    r1, s1 = c1[0], c1[1]
    r2, s2 = c2[0], c2[1]
    ri1, ri2 = RANK_ORDER[r1], RANK_ORDER[r2]
    if ri1 < ri2:
        r1, r2 = r2, r1
        s1, s2 = s2, s1
    if r1 == r2:
        return r1 + r2
    elif s1 == s2:
        return r1 + r2 + 's'
    else:
        return r1 + r2 + 'o'


# ============================================================
# Equity Engines
# ============================================================

def mc_equity(hole, board, opp_known=None, n=50):
    """Monte Carlo equity estimation."""
    try:
        excluded = set(str(c) for c in hole + board + (opp_known or []))
        remaining = [c for c in ALL_52 if str(c) not in excluded]

        need_board = 5 - len(board)
        need_opp = 2 - len(opp_known or [])
        total = need_board + need_opp

        if len(remaining) < total:
            return 0.5

        wins = ties = 0
        known_opp = opp_known or []
        for _ in range(n):
            sample = random.sample(remaining, total)
            if opp_known:
                opp = list(known_opp) + sample[:need_opp]
                bd = list(board) + sample[need_opp:]
            else:
                opp = sample[:2]
                bd = list(board) + sample[2:]

            my_s = eval7.evaluate(list(hole) + bd)
            opp_s = eval7.evaluate(opp + bd)

            if my_s > opp_s:
                wins += 1
            elif my_s == opp_s:
                ties += 1

        return (wins + ties * 0.5) / n
    except Exception:
        return 0.5

# We use MC for turn to avoid excessive enumeration loop time during action
def exact_equity_river(hole, board, opp_known=None):
    """Exact equity on the river by enumeration."""
    try:
        excluded = set(str(c) for c in hole + board + (opp_known or []))
        remaining = [c for c in ALL_52 if str(c) not in excluded]

        wins = total = 0.0
        if opp_known:
            for opp2 in remaining:
                my_s = eval7.evaluate(list(hole) + list(board))
                opp_s = eval7.evaluate(list(opp_known) + [opp2] + list(board))
                wins += 1 if my_s > opp_s else (0.5 if my_s == opp_s else 0)
                total += 1
        else:
            for c1, c2 in combinations(remaining, 2):
                my_s = eval7.evaluate(list(hole) + list(board))
                opp_s = eval7.evaluate([c1, c2] + list(board))
                wins += 1 if my_s > opp_s else (0.5 if my_s == opp_s else 0)
                total += 1
        return wins / total if total > 0 else 0.5
    except Exception:
        return mc_equity(hole, board, opp_known, MC_SIMS_FLOP)


def get_equity(hole, board, opp_known=None):
    """Smart equity dispatch."""
    n_board = len(board)
    if n_board == 5:
        return exact_equity_river(hole, board, opp_known)
    else:
        return mc_equity(hole, board, opp_known, MC_SIMS_FLOP)


# ============================================================
# Geometric Sizing
# ============================================================

def geometric_bet_size(pot, stack, streets_left):
    if streets_left <= 0:
        return stack
    spr = stack / max(1, pot)
    growth = (spr + 1) ** (1.0 / streets_left) - 1
    bet = int(pot * growth)
    bet = max(int(pot * 0.33), bet)
    if streets_left > 1:
        bet = min(int(pot * 1.5), bet)
    return bet


# ============================================================
# Opponent Model
# ============================================================

class OppModel:
    def __init__(self):
        self.raises = 0
        self.total = 0
        self.shove_count = 0     # times opp shoves (bet > 3x pot)
        self.postflop_hands = 0  # hands that reached post-flop

    def is_aggro(self, threshold=0.35):
        if self.total < 8:
            return False
        return self.raises / self.total > threshold

    def is_shove_bot(self):
        """Detect opponents who constantly all-in shove."""
        if self.postflop_hands < 5:
            return False
        return self.shove_count / self.postflop_hands > 0.25



# ----------- INIT --------------

class Player(BaseBot):
    def __init__(self) -> None:
        self.opp = OppModel()
        self.revealed_opp_card = None
        self.opp_has_info = False
        self.auction_won = False
        self.auction_done = False
        self.we_bet_this_hand = False

        self.loser_cfr_table = {} 
        self.hole_cards_eval7 = []
        self.flop_history_str = "11" # Default to check-check
        # Unpack everything on startup
        self.loser_cfr_table, self.flop_centroids, self.turn_centroids = self._decompress_table(MASTER_DATA)
    
    def _decompress_table(self, b64_string):
        # Unpacks the single string into the three required strategy components.            
        json_str = zlib.decompress(base64.b64decode(b64_string)).decode('utf-8')
        master_data = json.loads(json_str)
        
        # Convert CFR integer probabilities (0-100) back to floats (0.0-1.0)
        cfr_table = {k: [p / 100.0 for p in v] for k, v in master_data["cfr_table"].items()}
        
        return cfr_table, master_data["flop_centroids"], master_data["turn_centroids"]
        
    def on_hand_start(self, game_info: GameInfo, current_state: PokerState) -> None:
        self.hole_cards_eval7 = [eval7.Card(c) for c in current_state.my_hand]
        self.flop_history_str = "11" # Default to check-check

    def on_hand_end(self, game_info: GameInfo, current_state: PokerState) -> None: 
        self.revealed_opp_card = None
        self.opp_has_info = False
        self.auction_won = False
        self.auction_done = False
        self.we_bet_this_hand = False
        self.opp.total += 1

        hand = current_state.my_hand
        self._bucket = canonical_hand(hand[0], hand[1])
        self._preflop_eq = PREFLOP_EQUITY.get(self._bucket, 0.40)
        self._hole = [eval7.Card(str(c)) for c in hand]

    
    def _update_auction_state(self, state):
        if self.auction_done:
            return
        if state.street in ('turn', 'river', 'flop'):
            if state.street == 'flop' and state.opp_revealed_cards:
                self.auction_done = True
                self.revealed_opp_card = eval7.Card(state.opp_revealed_cards[0])
                self.auction_won = True
            elif state.street in ('turn', 'river'):
                self.auction_done = True
                if state.opp_revealed_cards:
                    self.revealed_opp_card = eval7.Card(state.opp_revealed_cards[0])
                    self.auction_won = True
                else:
                    self.opp_has_info = True

    # ============================================================
    # Auction — True Value Bidding
    # ============================================================

    def _handle_auction(self, gi, s):
        board = [eval7.Card(str(c)) for c in s.board] if s.board else []
        eq = mc_equity(self._hole, board, None, MC_SIMS_AUCTION)

        pot = s.pot
        my_chips = s.my_chips

        # CRITICAL FIX 1: Bid exact true value!
        # In second-price auctions, bidding exactly what you value it at is dominant.
        # If opponent pays 500, they win but must pay our bid (e.g. 20).
        # We don't bid 0, we bid 20 so THEY pay 20 to get the info!

        # Info value = equity_swing * expected_pot
        uncertainty = 1.0 - abs(eq - 0.5) * 2.0  # max at eq=0.5
        equity_swing = 0.12 + 0.10 * uncertainty  # 12-22%

        # Expected remaining pot value (current pot * conservative future multiplier)
        expected_pot = pot * 2.0

        # True value of info
        true_value = int(equity_swing * expected_pot)

        # Tie Risk: In a second-price auction, if both bid the same amount, both pay their full bids!
        # Do not multiply the true value. Simply bid the true value, with a tiny offset (-2 to +2).
        bid = true_value + random.choice([-2, -1, 0, 1, 2])
        
        return ActionBid(max(0, min(bid, my_chips)))

    def get_move(self, game_info: GameInfo, current_state: PokerState):
        street = current_state.street
        if street == 'pre-flop': return self._handle_preflop(game_info, current_state)
        elif street == 'auction': return self._handle_auction(game_info, current_state)
        
        if len(current_state.opp_revealed_cards) > 0:
            return self._handle_winner_state(current_state)
        else:
            return self._handle_loser_state(current_state)

    def _handle_preflop(self, game_info, s):
        eq = self._preflop_eq
        cost = s.cost_to_call
        pot = s.pot

        pot_odds = cost / (pot + cost) if cost > 0 else 0.0
        already_acted = s.my_wager > SMALL_BLIND

        # === CRITICAL FIX: Detect pre-flop all-in shoves ===
        # If opponent shoves all-in pre-flop (cost > 500), only call with monsters
        if cost > 500:
            if eq >= 0.70:  # Only top hands: AA, KK, QQ, JJ, AKs
                return ActionCall() if s.can_act(ActionCall) else ActionCheck()
            if s.can_act(ActionCheck):
                return ActionCheck()
            return ActionFold()

        # Handle opponent 3-bet / re-raise when we have already acted
        if already_acted and cost > 0:
            if eq >= 0.65:
                # 4-Bet Shove with premiums
                if s.can_act(ActionRaise):
                    return ActionRaise(s.raise_bounds[1])
                return ActionCall() if s.can_act(ActionCall) else ActionCheck()
            elif eq >= pot_odds + 0.05:
                return ActionCall() if s.can_act(ActionCall) else ActionCheck()
            else:
                return ActionCheck() if s.can_act(ActionCheck) else ActionFold()

        # If opponent makes a big raise (cost > 200), need strong hand
        if cost > 200:
            if eq >= 0.60:
                return ActionCall() if s.can_act(ActionCall) else ActionCheck()
            if s.can_act(ActionCheck):
                return ActionCheck()
            return ActionFold()

        # Premium (top ~15%): Raise
        if eq >= 0.60:
            if s.can_act(ActionRaise):
                lo, hi = s.raise_bounds
                target = max(lo, min(hi, int(s.my_wager + 3.5 * BIG_BLIND)))
                return ActionRaise(target)
            return ActionCall() if s.can_act(ActionCall) else ActionCheck()

        # Good (top ~40%): Call if pot odds good
        if eq >= 0.45:
            if cost == 0:
                if s.can_act(ActionRaise) and random.random() < 0.20:
                    lo, hi = s.raise_bounds
                    return ActionRaise(max(lo, min(hi, int(s.my_wager + 2.5 * BIG_BLIND))))
                return ActionCheck()
            if eq >= pot_odds + 0.05:
                return ActionCall() if s.can_act(ActionCall) else ActionCheck()
            if s.can_act(ActionCheck):
                return ActionCheck()
            return ActionFold()

        # Marginal: Cheap calls only
        if eq >= 0.35:
            if cost == 0:
                return ActionCheck()
            if cost <= BIG_BLIND and eq >= pot_odds:
                return ActionCall() if s.can_act(ActionCall) else ActionCheck()
            if s.can_act(ActionCheck):
                return ActionCheck()
            return ActionFold()

        # Trash
        if s.can_act(ActionCheck):
            return ActionCheck()
        return ActionFold()


    def _river_mdf_logic(self, current_state: PokerState):
        """
        TRACK B (River): Pure Math Heuristics (< 1ms).
        Executes when the offline CFR tree is truncated.
        """
        board_eval7 = [eval7.Card(c) for c in current_state.board]
        
        # 1. Calculate Absolute River Equity
        # Since there are no more community cards to deal, equity variance is much lower.
        # 400 iterations provides a highly accurate estimate in under 0.5ms.
        equity = self._fast_equity(self.hole_cards_eval7, board_eval7, iterations=400)
        
        facing_bet = not current_state.can_act(ActionCheck)
        
        # ---------------------------------------------------------------------
        # SCENARIO A: Defense (We are facing a bet)
        # ---------------------------------------------------------------------
        if facing_bet:
            # Minimum Defense Frequency (MDF) Proxy
            # To stop the omniscient opponent from bluffing 100% of the time, we must call.
            # However, because they see our card, we cannot call with marginal "bluff catchers".
            # We use a strict > 0.60 absolute equity threshold. This mathematically ensures 
            # we are only defending with the absolute top tier of our surviving range.
            
            if equity > 0.60:
                return ActionCall()
                
            return ActionFold() if current_state.can_act(ActionFold) else ActionCheck()
            
        # ---------------------------------------------------------------------
        # SCENARIO B: Offense (We act first OR opponent checked to us)
        # ---------------------------------------------------------------------
        else:
            # Split-Reality Value Betting
            # The opponent has X-ray vision on one card. If we bet, they will play perfectly,
            # instantly folding their trash and only calling with hands that beat us.
            # Therefore, we ONLY bet if our hand is a near-absolute monster (> 85% equity).
            
            if equity > 0.85 and current_state.can_act(ActionRaise):
                pot = sum(current_state.pot) if isinstance(current_state.pot, list) else current_state.pot
                min_r, max_r = current_state.raise_bounds
                
                # We map to our "raise_50" sizing logic to extract safe value
                target = int(pot * 0.5)
                
                # Clamp the bet to engine bounds to prevent illegal move penalties
                target = max(min_r, min(target, max_r))
                return ActionRaise(target)
                
            # If we don't have a monster, we happily check and take the free showdown
            return ActionCheck()

    def _handle_winner_state(self, current_state: PokerState):
        opp_card_str = current_state.opp_revealed_cards[0]
        board_eval7 = [eval7.Card(c) for c in current_state.board]
        collapsed_range = self._get_collapsed_range(opp_card_str, current_state)
        equity_vs_range = self._eval7_equity_vs_range(self.hole_cards_eval7, collapsed_range, board_eval7)
        
        if equity_vs_range > 0.60 and current_state.can_act(ActionRaise):
            return ActionRaise(current_state.raise_bounds[0])
        elif equity_vs_range < 0.30 and current_state.can_act(ActionFold):
            return ActionFold()
            
        return self._river_mdf_logic(current_state)
   
    # --------------------------------------
    # ------ SORTED ------------------------
    # --------------------------------------

    def _handle_loser_state(self, current_state: PokerState):
        """TRACK B: Defensive Offline CFR lookup with Positional Mapping & Debugging."""
        street = current_state.street
        
        if street in ['flop', 'turn']:
            board_eval7 = [eval7.Card(c) for c in current_state.board]
            
            # 1. Extract live features
            live_eq = self._fast_equity(self.hole_cards_eval7, board_eval7, 500)
            live_wet = self._calculate_board_wetness(board_eval7)
            
            # THE FIX: Scale by 1000 to match the integer compression of the centroids
            feature_vector = [live_eq * 1000.0, live_wet * 1000.0]
            
            # 2. Get the abstract bucket ID 
            bucket_id = self._get_closest_centroid(feature_vector, street)
            
            # 3. THE POSITIONAL MAPPING FIX
            facing_bet = not current_state.can_act(ActionCheck)
            hist_suffix = "2" if facing_bet else "1"
            
            strategy = None
            abstract_state = ""
            
            if street == 'flop':
                # Flop keys are exact: f259_1 or f259_2
                abstract_state = f"f{bucket_id}_{hist_suffix}"
                strategy = self.loser_cfr_table.get(abstract_state)
            else:
                # Turn keys have legacy flop history (e.g., t259_11t1). 
                target_prefix = f"t{bucket_id}_"
                target_suffix = f"t{hist_suffix}"
                
                for key, strat in self.loser_cfr_table.items():
                    if key.startswith(target_prefix) and key.endswith(target_suffix):
                        strategy = strat
                        abstract_state = key
                        break
            
            # 4. Graceful Fallback Handle & DEBUGGERS
            if strategy is None:
                if facing_bet:
                    safe_fallback = [0.40, 0.40, 0.20, 0.0] # Fold often to bets, occasionally raise
                else:
                    safe_fallback = [0.0, 0.80, 0.15, 0.05] # Mostly check, rarely lead out
                    
                # --- DEBUGGER: MISS ---
                expected_key = f"f{bucket_id}_{hist_suffix}" if street == 'flop' else f"t{bucket_id}_...t{hist_suffix}"
                print(f"[CFR MISS] Missing '{expected_key}'. Using fallback -> {safe_fallback}")
                
                return self._sample_action(safe_fallback, current_state)
                
            # --- DEBUGGER: HIT ---
            print(f"[CFR HIT] Found '{abstract_state}' -> {strategy}")
            return self._sample_action(strategy, current_state)
            
        elif street == 'river':
            return self._river_mdf_logic(current_state)

